```typescript
// middleware.ts (project root)
import { NextRequest, NextResponse } from 'next/server';
import { jwtVerify } from 'jose';

const PUBLIC_ROUTES = ['/', '/login', '/signup', '/api/auth/login', '/api/auth/refresh'];
const JWT_SECRET = new TextEncoder().encode(process.env.JWT_SECRET!);

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl;

  if (PUBLIC_ROUTES.some(route => pathname.startsWith(route))) {
    return NextResponse.next();
  }

  const token = req.headers.get('Authorization')?.replace('Bearer ', '');
  if (!token) {
    return NextResponse.redirect(new URL('/login', req.url));
  }

  try {
    const { payload } = await jwtVerify(token, JWT_SECRET);
    const requestHeaders = new Headers(req.headers);
    requestHeaders.set('x-user-id', payload.sub as string);
    return NextResponse.next({ request: { headers: requestHeaders } });
  } catch {
    return NextResponse.redirect(new URL('/login', req.url));
  }
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico).*)'],
};
```

Here's the refresh endpoint that reads the HttpOnly cookie and rotates the token:

```typescript
// app/api/auth/refresh/route.ts
import { cookies } from 'next/headers';
import { SignJWT } from 'jose';
import { db } from '@/lib/db';
import { sessions } from '@/lib/schema';
import { eq } from 'drizzle-orm';
import crypto from 'crypto';

export async function POST() {
  const cookieStore = await cookies();
  const refreshToken = cookieStore.get('refresh_token')?.value;

  if (!refreshToken) {
    return Response.json({ error: 'No refresh token' }, { status: 401 });
  }

  const tokenHash = crypto.createHash('sha256').update(refreshToken).digest('hex');
  const session = await db.select().from(sessions)
    .where(eq(sessions.refreshTokenHash, tokenHash)).get();

  if (!session || session.expiresAt < new Date()) {
    return Response.json({ error: 'Invalid or expired session' }, { status: 401 });
  }

  // Rotate: delete old, create new
  await db.delete(sessions).where(eq(sessions.id, session.id));
  const newRefreshToken = crypto.randomBytes(64).toString('hex');
  // ... create new session, issue new JWT
}
```

